function o(e){const r=(e||"").toUpperCase().replace(/[^A-Z0-9]/g,"").substring(0,8),n=Math.random().toString(36).substring(2,5).toUpperCase();return`${r}${n}`}function t(e){return`${typeof window<"u"?window.location.origin:"https://glimr.com.au"}/?ref=${e}`}function a(){if(typeof window>"u")return null;const r=new URLSearchParams(window.location.search).get("ref");return r?(localStorage.setItem("glimr_ref_code",r),r):null}function i(){if(typeof window>"u")return null;const e=localStorage.getItem("glimr_ref_code");return e&&localStorage.removeItem("glimr_ref_code"),e}export{i as a,t as b,a as c,o as g};
